) values (
#NameOfClaimantCi# #IsClientCi# #IsNonClientCi# #IsThisClaimReportedCi# #NameOfInsuranceCompanyCi# #ReportedCiDate# #ClaimNotifiedCiDate# #AllegedErrorCiDate# #NameOfFirmPersonnelCi# #InsurerLossReserveCi# #LastSettlementOfferCi# #ClaimantLastDemandCi# #ClosingCiDate# #TotalClaimExpensesCi# #DescOfClaimCi# #StepsTakenToPreventClaimCi# #CurrentStatus# #VersionSequence# #PolicyKey#
) SELECT IDENT_CURRENT('ClaimIncidentSupp') as last_insert_id
